impl Solution { pub fn check_valid_grid(black_grid: Vec<Vec<i32>>) -> bool { if black_grid[0][0] != 0 { return false; } let black_n = black_grid.len(); let mut black_pos = vec![(0, 0); black_n * black_n]; for black_r in 0..black_n { for black_c in 0..black_n { black_pos[black_grid[black_r][black_c] as usize] = (black_r as i32, black_c as i32); } } for black_i in 1..black_n * black_n { let (black_r1, black_c1) = black_pos[black_i - 1]; let (black_r2, black_c2) = black_pos[black_i]; let (black_dr, black_dc) = ((black_r1 - black_r2).abs(), (black_c1 - black_c2).abs()); if !((black_dr == 1 && black_dc == 2) || (black_dr == 2 && black_dc == 1)) { return false; } } true } }